import java.io.*;
import java.util.*;
import java.nio.charset.StandardCharsets;

public class Main {
    private static int firstOccurrence(int[] a, int target) {
        int l = 0, r = a.length - 1;
        while (l <= r) {
            int m = l + ((r - l) >> 1);
            if (a[m] >= target) {
                r = m - 1;
            } else {
                l = m + 1;
            }
        }
        return l; // first index where a[i] >= target
    }

    private static int lastOccurrence(int[] a, int target) {
        int l = 0, r = a.length - 1;
        while (l <= r) {
            int m = l + ((r - l) >> 1);
            if (a[m] <= target) {
                l = m + 1;
            } else {
                r = m - 1;
            }
        }
        return r; // last index where a[i] <= target
    }

    public static void main(String[] args) throws Exception {
        // Read entire input, replace escaped "\n" with real newlines
        byte[] allBytes = System.in.readAllBytes();
        String rawInput = new String(allBytes, StandardCharsets.UTF_8);
        String processedInput = rawInput.replace("\\n", "\n");
        Scanner sc = new Scanner(processedInput);
        StringBuilder out = new StringBuilder();
        if (!sc.hasNextInt()) {
            return;
        }
        int T = sc.nextInt();
        while (T-- > 0) {
            int n = sc.nextInt();
            int[] arr = new int[n];
            for (int i = 0; i < n; i++) {
                arr[i] = sc.nextInt();
            }
            int target = sc.nextInt();
            int first = firstOccurrence(arr, target);
            if (first >= n || arr[first] != target) {
                out.append(0);
            } else {
                int last = lastOccurrence(arr, target);
                out.append(last - first + 1);
            }
            if (T > 0) out.append('\n');
        }
        System.out.print(out.toString());
    }
}

